-		if len(diffOutput) == 0 {
-			return fmt.Errorf("failed to get diff: %w", err)
-		}
-	}
-
-	if len(strings.TrimSpace(string(diffOutput))) == 0 {
-		fmt.Println("  (no differences)")
-	} else {
-		fmt.Print(string(diffOutput))
-	}
-
-	return nil
